34	export class BackupWorker extends BaseWorker {
35	  readonly type = 'backup';
36	
37	  async handle(payload: object): Promise<void> {
38	    const { backupId, type, storagePath } = payload as BackupPayload;
39	
40	    // Mark running
41	    await db.backupRecord.update({
42	      where: { id: backupId },
43	      data: { status: 'running' },
44	    });
45	
46	    try {
47	      const backupDir = path.join(config.BACKUP_PATH, backupId);
48	      await fs.mkdir(backupDir, { recursive: true });
49	
50	      const dumpPath = path.join(backupDir, 'dump.sql');
51	      const metaPath = path.join(backupDir, 'backup-meta.json');
52	
53	      // Parse DATABASE_URL and run mysqldump
54	      const db_url = process.env['DATABASE_URL'];
55	      if (!db_url) throw new Error('DATABASE_URL not set');
56	      const { host, port, user, pass, dbname } = parseDbUrl(db_url);
57	
58	      execSync(
59	        `mysqldump -h ${host} -P ${port} -u ${user} ${dbname} > "${dumpPath}"`,
60	        {
61	          stdio: ['ignore', 'pipe', 'pipe'],
62	          env: withMysqlPassword(pass),
63	        },
64	      );
65	
66	      // Write metadata
67	      const meta = {
68	        backupId,
69	        type,
70	        storagePath,
71	        startedAt: new Date().toISOString(),
72	        dumpFile: 'dump.sql',
73	      };
74	      await fs.writeFile(metaPath, JSON.stringify(meta, null, 2), 'utf-8');
75	
76	      const dumpStat = await fs.stat(dumpPath);
77	
78	      // Delete expired backups
79	      const deleted = await deleteExpiredBackups();
80	      logger.info({ deletedCount: (deleted as any).count ?? 0 }, 'Backup worker: expired records purged');
81	
82	      await db.backupRecord.update({
83	        where: { id: backupId },
84	        data: {
85	          status: 'completed',
86	          sizeBytes: BigInt(dumpStat.size),
87	          completedAt: new Date(),
88	        },
89	      });
90	
91	      logger.info({ backupId, type, sizeBytes: dumpStat.size }, 'Backup worker: completed');
92	    } catch (err) {
93	      await db.backupRecord.update({
94	        where: { id: backupId },
95	        data: { status: 'failed', completedAt: new Date() },
96	      });
97	      throw err;
98	    }
99	  }
100	}
