33	export class RestoreWorker extends BaseWorker {
34	  readonly type = 'restore';
35	
36	  async handle(payload: object): Promise<void> {
37	    const { restoreRunId, backupId } = payload as RestorePayload;
38	
39	    await db.restoreRun.update({
40	      where: { id: restoreRunId },
41	      data: { status: 'running' },
42	    });
43	
44	    try {
45	      const backupDir = path.join(config.BACKUP_PATH, backupId);
46	      const dumpPath = path.join(backupDir, 'dump.sql');
47	      const metaPath = path.join(backupDir, 'backup-meta.json');
48	
49	      const [dumpExists, metaExists] = await Promise.all([
50	        fs.access(dumpPath).then(() => true).catch(() => false),
51	        fs.access(metaPath).then(() => true).catch(() => false),
52	      ]);
53	
54	      const verificationResult: Record<string, unknown> = {
55	        dumpFilePresent: dumpExists,
56	        metadataFilePresent: metaExists,
57	        checkedAt: new Date().toISOString(),
58	      };
59	
60	      if (!dumpExists) {
61	        verificationResult.status = 'dump_missing';
62	        verificationResult.parseable = false;
63	        logger.warn({ backupId, restoreRunId }, 'Restore worker: dump.sql not found');
64	
65	        await db.restoreRun.update({
66	          where: { id: restoreRunId },
67	          data: {
68	            status: 'failed',
69	            verificationResult: JSON.stringify(verificationResult),
70	            completedAt: new Date(),
71	          },
72	        });
73	        return;
74	      }
75	
76	      // Read metadata
77	      if (metaExists) {
78	        const metaRaw = await fs.readFile(metaPath, 'utf-8');
79	        const meta = JSON.parse(metaRaw) as Record<string, unknown>;
80	        verificationResult.backupType = meta.type;
81	        verificationResult.backupStartedAt = meta.startedAt;
82	      }
83	
84	      const db_url = process.env['DATABASE_URL'];
85	      if (!db_url) throw new Error('DATABASE_URL not set');
86	      const { host, port, user, pass, dbname } = parseDbUrl(db_url);
87	
88	      // Execute the full database restore from dump.sql
89	      // This is an admin-triggered operation — the administrator is expected to
90	      // understand this replaces all current data with the backup snapshot.
91	      execSync(
92	        `mysql -h ${host} -P ${port} -u ${user} ${dbname} < "${dumpPath}"`,
93	        {
94	          stdio: ['ignore', 'pipe', 'pipe'],
95	          env: withMysqlPassword(pass),
96	        },
97	      );
98	
99	      const dumpStat = await fs.stat(dumpPath);
100	      verificationResult.parseable = true;
101	      verificationResult.restoredBytes = dumpStat.size;
102	      verificationResult.status = 'restored';
103	
104	      await db.restoreRun.update({
105	        where: { id: restoreRunId },
106	        data: {
107	          status: 'completed',
108	          verificationResult: JSON.stringify(verificationResult),
109	          completedAt: new Date(),
110	        },
111	      });
112	
113	      logger.info({ restoreRunId, backupId, restoredBytes: dumpStat.size }, 'Restore worker: completed');
114	    } catch (err) {
115	      const sanitized = sanitizeErrorMessage(String(err));
116	      await db.restoreRun.update({
117	        where: { id: restoreRunId },
118	        data: {
119	          status: 'failed',
120	          verificationResult: JSON.stringify({ error: sanitized }),
121	          completedAt: new Date(),
122	        },
123	      });
124	      throw err;
125	    }
126	  }
127	}
