1	import * as fs from 'fs';
2	import * as path from 'path';
3	import axios from 'axios';
4	import { BaseWorker } from './base-worker.js';
5	import { db } from '../../app/container.js';
6	import { decrypt } from '../../common/encryption/aes256.js';
7	import { logger } from '../../common/logging/logger.js';
8	import { getOrCreateBreaker } from '../../common/circuit-breaker/circuit-breaker.js';
9	import { addTrackingUpdate, upsertSyncCursor } from '../../modules/logistics/repository.js';
10	
11	const carrierApiBreaker = getOrCreateBreaker('carrier-sync-rest-api', {
12	  failureThreshold: 5,
13	  successThreshold: 2,
14	  openTimeoutMs: 5 * 60 * 1000,
15	});
16	
17	export class CarrierSyncWorker extends BaseWorker {
18	  readonly type = 'carrier_sync';
19	
20	  async handle(payload: object): Promise<void> {
21	    const { carrierId } = payload as { carrierId: string };
22	
23	    const carrier = await db.carrier.findUnique({ where: { id: carrierId } });
24	    if (!carrier) {
25	      logger.warn({ carrierId }, 'Carrier not found for sync');
26	      return;
27	    }
28	
29	    const connectorConfig = carrier.connectorConfig ? decrypt(carrier.connectorConfig) : null;
30	    const cursor = await db.carrierSyncCursor.findUnique({ where: { carrierId } });
31	
32	    try {
33	      if (carrier.connectorType === 'manual') {
34	        // No-op for manual carriers — just update cursor timestamp
35	        logger.info({ carrierId, connectorType: 'manual' }, 'Manual carrier sync: no-op');
36	
37	      } else if (carrier.connectorType === 'rest_api') {
38	        const cfg = JSON.parse(connectorConfig ?? '{}') as {
39	          apiUrl: string;
40	          apiKey?: string;
41	          timeoutMs?: number;
42	        };
43	
44	        const since = cursor?.lastSyncAt?.toISOString() ?? '';
45	        const response = await carrierApiBreaker.execute(() =>
46	          axios.get<unknown[]>(cfg.apiUrl, {
47	            params: { since },
48	            headers: cfg.apiKey ? { Authorization: `Bearer ${cfg.apiKey}` } : {},
49	            timeout: cfg.timeoutMs ?? 10000,
50	          }),
51	        );
52	
53	        const updates = Array.isArray(response.data) ? response.data : [];
54	        for (const update of updates) {
55	          const u = update as { shipmentId?: string; status?: string; location?: string };
56	          if (u.shipmentId && u.status) {
57	            const shipment = await db.shipment.findUnique({
58	              where: { id: u.shipmentId },
59	              select: { carrierId: true },
60	            });
61	            if (!shipment || shipment.carrierId !== carrierId) {
62	              logger.warn(
63	                { carrierId, shipmentId: u.shipmentId },
64	                'Carrier sync: shipment ownership mismatch — skipping update',
65	              );
66	              continue;
67	            }
68	            await addTrackingUpdate(u.shipmentId, u.status, u.location ?? null, 'carrier_sync');
69	          }
70	        }
71	
72	        await upsertSyncCursor(carrierId, {
73	          lastSyncAt: new Date(),
74	          lastSuccessCursor: new Date().toISOString(),
75	          errorState: null,
76	        });
77	
78	        logger.info({ carrierId, updatesProcessed: updates.length }, 'Carrier sync: rest_api completed');
79	
80	      } else if (carrier.connectorType === 'file_drop') {
81	        const cfg = JSON.parse(connectorConfig ?? '{}') as {
82	          watchDirectory: string;
83	          processedDirectory?: string;
84	        };
85	
86	        const watchDir = cfg.watchDirectory;
87	        const processedDir = cfg.processedDirectory ?? path.join(watchDir, 'processed');
88	
89	        if (!fs.existsSync(watchDir)) {
90	          logger.warn({ carrierId, watchDir }, 'Carrier sync: watch directory not found');
91	          await upsertSyncCursor(carrierId, { lastSyncAt: new Date(), errorState: null });
92	          return;
93	        }
94	
95	        fs.mkdirSync(processedDir, { recursive: true });
96	
97	        const files = fs.readdirSync(watchDir).filter((f) => f.endsWith('.json'));
98	        let updatesProcessed = 0;
99	
100	        for (const file of files) {
101	          const filePath = path.join(watchDir, file);
102	          const stat = fs.statSync(filePath);
103	
104	          // Skip files not modified after last sync
105	          if (cursor?.lastSyncAt && stat.mtime <= cursor.lastSyncAt) continue;
106	
107	          try {
108	            const content = fs.readFileSync(filePath, 'utf-8');
109	            const updates = JSON.parse(content) as unknown[];
110	            const updateList = Array.isArray(updates) ? updates : [updates];
111	
112	            for (const update of updateList) {
113	              const u = update as { shipmentId?: string; status?: string; location?: string };
114	              if (u.shipmentId && u.status) {
115	                const shipment = await db.shipment.findUnique({
116	                  where: { id: u.shipmentId },
117	                  select: { carrierId: true },
118	                });
119	                if (!shipment || shipment.carrierId !== carrierId) {
120	                  logger.warn(
121	                    { carrierId, shipmentId: u.shipmentId },
122	                    'Carrier sync: shipment ownership mismatch — skipping update',
123	                  );
124	                  continue;
125	                }
126	                await addTrackingUpdate(u.shipmentId, u.status, u.location ?? null, 'carrier_sync');
127	                updatesProcessed++;
128	              }
129	            }
130	
131	            // Move processed file
132	            fs.renameSync(filePath, path.join(processedDir, file));
133	          } catch (fileErr) {
134	            logger.warn({ carrierId, file, err: String(fileErr) }, 'Carrier sync: failed to process file');
135	          }
136	        }
137	
138	        await upsertSyncCursor(carrierId, {
139	          lastSyncAt: new Date(),
140	          lastSuccessCursor: new Date().toISOString(),
141	          errorState: null,
142	        });
143	
144	        logger.info({ carrierId, updatesProcessed }, 'Carrier sync: file_drop completed');
145	      }
146	
147	      // Upsert sync cursor with updated timestamp for all types
148	      await db.carrierSyncCursor.upsert({
149	        where: { carrierId },
150	        update: { lastSyncAt: new Date(), errorState: null },
151	        create: {
152	          carrierId,
153	          lastSyncAt: new Date(),
154	          lastSuccessCursor: cursor?.lastSuccessCursor ?? null,
155	          errorState: null,
156	        },
157	      });
158	
159	      logger.info({ carrierId }, 'Carrier sync cursor updated');
160	    } catch (err) {
161	      const errorState = String(err);
162	      await db.carrierSyncCursor.upsert({
163	        where: { carrierId },
164	        update: { lastSyncAt: new Date(), errorState },
165	        create: {
166	          carrierId,
167	          lastSyncAt: new Date(),
168	          lastSuccessCursor: cursor?.lastSuccessCursor ?? null,
169	          errorState,
170	        },
171	      });
172	      logger.error({ carrierId, err: errorState }, 'Carrier sync failed');
173	      throw err;
174	    }
175	  }
176	}
