7	export async function calculateFee(orgId: string, input: ShippingFeeCalculationInput) {
8	  const template = await repo.findTemplateByRegionAndTier(
9	    orgId,
10	    input.regionCode,
11	    input.tier,
12	    input.itemCount,
13	  );
14	
15	  if (!template) {
16	    throw new NotFoundError(
17	      `No active shipping fee template found for region '${input.regionCode}', tier '${input.tier}'`,
18	    );
19	  }
20	
21	  const surcharges = template.surcharges.map((s) => ({
22	    condition: s.condition,
23	    surchargeAmount: parseFloat(s.surchargeAmount.toString()),
24	  }));
25	
26	  return calculateShippingFee(
27	    {
28	      id: template.id,
29	      baseFee: parseFloat(template.baseFee.toString()),
30	      baseWeightLb: parseFloat(template.baseWeightLb.toString()),
31	      perAdditionalLbFee: parseFloat(template.perAdditionalLbFee.toString()),
32	    },
33	    surcharges,
34	    input.weightLb,
35	    input.applicableSurcharges,
36	  );
37	}
