41	export async function createShipment(orgId: string, data: {
42	  warehouseId: string;
43	  carrierId: string;
44	  trackingNumber?: string;
45	  parcels: { description: string; weightLb: number; quantity: number }[];
46	}) {
47	  const warehouse = await repo.findWarehouseById(data.warehouseId);
48	  if (!warehouse || warehouse.orgId !== orgId) {
49	    throw new NotFoundError('Warehouse not found in this organization');
50	  }
51	
52	  const carrier = await repo.findCarrierById(data.carrierId);
53	  if (!carrier || carrier.orgId !== orgId) {
