60	export async function recordTrackingUpdate(
61	  shipmentId: string,
62	  status: string,
63	  location: string | null,
64	  source: string,
65	) {
66	  const shipment = await repo.findShipmentById(shipmentId);
67	  if (!shipment) throw new NotFoundError('Shipment not found');
68	
69	  await repo.addTrackingUpdate(shipmentId, status, location, source);
70	
71	  if (status === 'delivered') {
72	    await repo.updateShipmentStatus(shipmentId, 'delivered', { deliveredAt: new Date() });
73	  } else if (status === 'shipped') {
74	    await repo.updateShipmentStatus(shipmentId, 'shipped', { shippedAt: new Date() });
75	  } else if (status === 'in_transit') {
76	    await repo.updateShipmentStatus(shipmentId, 'in_transit');
