1	import { createHmac, timingSafeEqual, randomBytes } from 'crypto';
2	
3	export function signRequest(payload: string, secret: string, timestampMs: number): string {
4	  return createHmac('sha256', secret)
5	    .update(`${timestampMs}:${payload}`)
6	    .digest('hex')
7	    .toLowerCase();
8	}
9	
10	export function verifySignature(
11	  payload: string,
12	  secret: string,
13	  signature: string,
14	  timestampMs: number,
15	  maxAgeMs = 5 * 60 * 1000,
16	): boolean {
17	  if (Math.abs(Date.now() - timestampMs) > maxAgeMs) {
18	    return false;
19	  }
20	
21	  const expected = signRequest(payload, secret, timestampMs);
22	
23	  try {
24	    const expectedBuf = Buffer.from(expected, 'hex');
25	    const receivedBuf = Buffer.from(signature.toLowerCase(), 'hex');
26	
27	    if (expectedBuf.length !== receivedBuf.length) {
28	      return false;
29	    }
30	
31	    return timingSafeEqual(expectedBuf, receivedBuf);
32	  } catch {
33	    return false;
34	  }
35	}
36	
37	export function generateSigningSecret(): string {
38	  return randomBytes(32).toString('hex');
39	}
