187	/**
188	 * Calculates the shipping fee given a template and input parameters.
189	 * Formula: baseFee + max(0, (weight - baseWeight)) * perAdditionalLbFee + surcharges
190	 */
191	export function calculateShippingFee(
192	  template: Pick<ShippingFeeTemplate, 'id' | 'baseFee' | 'baseWeightLb' | 'perAdditionalLbFee'>,
193	  surcharges: Pick<ShippingFeeSurcharge, 'condition' | 'surchargeAmount'>[],
194	  weightLb: number,
195	  applicableConditions: string[]
196	): ShippingFeeCalculationResult {
197	  const baseFee = template.baseFee;
198	  const overageWeight = Math.max(0, weightLb - template.baseWeightLb);
199	  const additionalWeightFee = parseFloat((overageWeight * template.perAdditionalLbFee).toFixed(2));
200	
201	  const applicableSurcharges = surcharges.filter((s) =>
202	    applicableConditions.includes(s.condition)
203	  );
204	  const surchargeTotal = parseFloat(
205	    applicableSurcharges.reduce((sum, s) => sum + s.surchargeAmount, 0).toFixed(2)
206	  );
207	
208	  const totalFee = parseFloat((baseFee + additionalWeightFee + surchargeTotal).toFixed(2));
209	
210	  const breakdown: { label: string; amount: number }[] = [
211	    { label: 'Base fee', amount: baseFee },
212	  ];
213	  if (additionalWeightFee > 0) {
214	    breakdown.push({
215	      label: `Additional weight (${overageWeight.toFixed(2)} lb)`,
216	      amount: additionalWeightFee,
217	    });
218	  }
219	  for (const s of applicableSurcharges) {
220	    breakdown.push({ label: `Surcharge: ${s.condition}`, amount: s.surchargeAmount });
221	  }
222	
223	  return {
224	    baseFee,
225	    additionalWeightFee,
226	    surchargeTotal,
227	    totalFee,
228	    templateId: template.id,
229	    breakdown,
230	  };
231	}
